class Person():
    def __init__(self, förnamn, efternamn, födelseår):
      self.förnamn = förnamn
      self.efternamn = efternamn
      self.födelseår = födelseår

    def __lt__(self, other):
      if self.förnamn < other.förnamn:
        return True
      elif self.förnamn == other.förnamn:
        if self.efternamn < other.efternamn:
          return True
        else:
          return False
      else:
        return False

    def __eq__(self, other):
      if self.förnamn == other.förnamn and self.efternamn == other.efternamn: #Nu behöver både för-och efternamn vara samma för att objekten ska anses vara lika
        return True
      else:
        return False


    def __str__(self):
      return self.förnamn + " " + self.efternamn +": " + str(self.födelseår)


    def skrivIntro(self):
      print("Hej jag heter " + self.förnamn + " " + self.efternamn + " och jag är " + str(self.ålder) + " år gammal")

def huvudprogram():
  personlista = []
  personlista.append(Person("Ebru","Qvist", 2006))
  personlista.append(Person("Selim","Farin", 1999))
  personlista.append(Person("Felicia","Gröngöling", 2002))
  personlista.append(Person("Ebru","Hansson", 2004))

  första_personen = personlista[0]
  for index in range(1,len(personlista)):
    if första_personen == personlista[index]:
      print("Det finns två personer som heter ", första_personen.förnamn, första_personen.efternamn)
    else:
      print(första_personen.förnamn, första_personen.efternamn, "och", personlista[index].förnamn,personlista[index].efternamn, "heter inte samma sak.")



huvudprogram()
